package com.retail.retailstoremanagement.controller;
import com.retail.retailstoremanagement.dao.impl.JdbcUserDao;import com.retail.retailstoremanagement.service.AuthService;import com.retail.retailstoremanagement.util.RequestUtils;import jakarta.servlet.ServletException;import jakarta.servlet.annotation.WebServlet;import jakarta.servlet.http.*;import java.io.IOException;
@WebServlet("/users") public class UserServlet extends HttpServlet{private final AuthService service=new AuthService(new JdbcUserDao());protected void doGet(HttpServletRequest q,HttpServletResponse p)throws ServletException,IOException{try{q.setAttribute("users",service.findAll());q.setAttribute("flashSuccess",RequestUtils.consumeFlash(q,"flashSuccess"));q.setAttribute("flashError",RequestUtils.consumeFlash(q,"flashError"));q.getRequestDispatcher("/WEB-INF/views/users.jsp").forward(q,p);}catch(Exception e){throw new ServletException(e);}}protected void doPost(HttpServletRequest q,HttpServletResponse p)throws IOException{try{service.createUser(q.getParameter("username"),q.getParameter("password"),q.getParameter("fullName"),q.getParameter("role"));RequestUtils.flash(q,"flashSuccess","Đã tạo tài khoản.");}catch(Exception e){RequestUtils.flash(q,"flashError",e.getMessage());}p.sendRedirect(q.getContextPath()+"/users");}}
